          >
            <Package className="w-3.5 h-3.5" />
            <span className="hidden xs:inline">{isInventoryOpen ? 'Close Gear' : 'Open Gear'}</span>
            {isInventoryOpen ? <ChevronLeft className="w-3 h-3 md:hidden" /> : <ChevronDown className="w-3 h-3 md:hidden" />}
