                    <div className="min-w-0">
                      <h5 className="text-[10px] md:text-xs font-black text-stone-200 uppercase truncate">{skill.name}</h5>
                      <p className="text-[8px] md:text-[9px] text-stone-500 italic leading-tight line-clamp-1">
                        {skill.description}
