export default MainGameLayout;

import { PrimaryStats } from './Stats';
import { JobClass } from './JobClass';
import { Equipment, EquipmentSlotType } from './Equipment';

export type Gender = 'Male' | 'Female';

export type MercenaryStatus = 'VISITOR' | 'HIRED' | 'ON_EXPEDITION' | 'INJURED' | 'DEAD';

export type MercenaryEquipment = Record<EquipmentSlotType, Equipment | null>;

export interface Mercenary {
  id: string;
  name: string;
  gender: Gender;
  job: JobClass;
  level: number;
  stats: PrimaryStats; // Base/Initial attributes
  allocatedStats: PrimaryStats; // Points from leveling up
  bonusStatPoints: number; // New: Remaining points to be allocated by player

  // Vitals
  currentHp: number;
  maxHp: number;
  currentMp: number;
  maxMp: number;

  // Visuals
  icon?: string;
  sprite?: string;

  // Relationships
  affinity: number;
  visitCount: number;
  isUnique: boolean;

  // State
  lastVisitDay?: number;
  status: MercenaryStatus;
  assignedExpeditionId?: string;
  recoveryUntilDay?: number; // The day when the mercenary will recover from injury

  // Dungeon System
  expeditionEnergy: number;

  // Progression
  currentXp: number;
  xpToNextLevel: number;

  // Skills
  skillIds?: string[];

  // Equipment
  equipment: MercenaryEquipment;
}

import { Mercenary, Gender } from '../models/Mercenary';
import { NAMED_MERCENARIES } from '../data/mercenaries';
import { JobClass, JOB_STAT_WEIGHTS } from '../models/JobClass';
import { calculateMaxHp, calculateMaxMp, PrimaryStats, mergePrimaryStats } from '../models/Stats';
import { generateFullName } from './nameGenerator';
import { DUNGEON_CONFIG } from '../config/dungeon-config';
import { Equipment, EquipmentSlotType } from '../models/Equipment';

const distributeRandomPoints = (weights: PrimaryStats, points: number): PrimaryStats => {
    const stats = { str: 0, vit: 0, dex: 0, int: 0, luk: 0 };
    const totalWeight = weights.str + weights.vit + weights.dex + weights.int + weights.luk;

    if (totalWeight === 0) return stats;

    let remaining = points;
    const keys = ['str', 'vit', 'dex', 'int', 'luk'] as const;

    while (remaining > 0) {
        const rand = Math.random() * totalWeight;
        let cumulative = 0;
        for (const key of keys) {
            cumulative += weights[key];
            if (rand <= cumulative) {
                stats[key]++;
                remaining--;
                break;
            }
        }
    }
    return stats;
};

const generateBaseStats = (job: JobClass): PrimaryStats => {
    const weights = JOB_STAT_WEIGHTS[job];
    // Base stats at level 1: 20-25 points distributed randomly using weights
    const baseTotal = 20 + Math.floor(Math.random() * 5);
    return distributeRandomPoints(weights, baseTotal);
};

const defaultEquipment: Record<EquipmentSlotType, Equipment | null> = {
    MAIN_HAND: null,
    OFF_HAND: null,
    HEAD: null,
    BODY: null,
    HANDS: null,
    FEET: null,
    ACCESSORY: null
};

const calculateLevelDataFromTotalXp = (totalXp: number) => {
    let level = 1;
    let xpToNext = 100;
    let remainingXp = totalXp;

    while (remainingXp >= xpToNext) {
        remainingXp -= xpToNext;
        level++;
        xpToNext = level * 100;
    }

    return {
        level,
        currentXp: remainingXp,
        xpToNextLevel: xpToNext
    };
};

export const createRandomMercenary = (currentDay: number): Mercenary => {
    const jobKeys = Object.values(JobClass);
    const job = jobKeys[Math.floor(Math.random() * jobKeys.length)];

    const randomFactor = Math.random(); 
    const totalXp = Math.floor(Math.pow(randomFactor, 2) * 2500); 

    const { level, currentXp, xpToNextLevel } = calculateLevelDataFromTotalXp(totalXp);

    const baseStats = generateBaseStats(job);
    // Newly recruited mercenaries have some points pre-allocated but player gets the bonus points
    const bonusPoints = (level - 1) * 3;

    const merged = mergePrimaryStats(baseStats, { str: 0, vit: 0, dex: 0, int: 0, luk: 0 });
    const maxHp = calculateMaxHp(merged, level);
    const maxMp = calculateMaxMp(merged, level);

    const gender: Gender = Math.random() < 0.5 ? 'Male' : 'Female';
    const fullName = generateFullName(gender, job);

    return {
        id: `rnd_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        name: fullName,
        gender: gender,
        job: job,
        level: level,
        stats: baseStats,
        allocatedStats: { str: 0, vit: 0, dex: 0, int: 0, luk: 0 },
        bonusStatPoints: bonusPoints, // Give player all the level points to spend
        currentHp: maxHp,
        maxHp: maxHp,
        currentMp: maxMp,
        maxMp: maxMp,
        affinity: 0,
        visitCount: 1,
        isUnique: false,
        lastVisitDay: currentDay,
        icon: '👤',
        expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: currentXp,
        xpToNextLevel: xpToNextLevel,
        status: 'VISITOR',
        equipment: { ...defaultEquipment }
    };
};

// Added missing export required by TavernTab.tsx
export const getUnmetNamedMercenary = (knownMercenaries: Mercenary[]): Mercenary | null => {
    const unknownNamed = NAMED_MERCENARIES.filter(
        named => !knownMercenaries.some(known => known.id === named.id)
    );
    if (unknownNamed.length === 0) return null;
    return unknownNamed[Math.floor(Math.random() * unknownNamed.length)];
};

export const generateMercenary = (knownMercenaries: Mercenary[], currentDay: number): Mercenary => {
    const rand = Math.random();

    if (knownMercenaries.length > 0 && rand < 0.3) {
        const potentialRegulars = knownMercenaries.filter(m => m.lastVisitDay !== currentDay);
        if (potentialRegulars.length > 0) {
            const regular = potentialRegulars[Math.floor(Math.random() * potentialRegulars.length)];
            const merged = mergePrimaryStats(regular.stats, regular.allocatedStats);
            const maxHp = calculateMaxHp(merged, regular.level);
            const maxMp = calculateMaxMp(merged, regular.level);
            return { 
                ...regular,
                currentHp: maxHp,
                currentMp: maxMp,
                maxHp,
                maxMp,
                expeditionEnergy: regular.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
                currentXp: regular.currentXp ?? 0,
                xpToNextLevel: regular.xpToNextLevel ?? (regular.level * 100),
                equipment: regular.equipment || { ...defaultEquipment }
            }; 
        }
    }

    if (rand < 0.5) {
        const unknownNamed = NAMED_MERCENARIES.filter(
            named => !knownMercenaries.some(known => known.id === named.id)
        );
        if (unknownNamed.length > 0) {
            const merc = unknownNamed[Math.floor(Math.random() * unknownNamed.length)];
            return {
                ...merc,
                visitCount: 1, 
                lastVisitDay: currentDay
            } as Mercenary;
        }
    }

    return createRandomMercenary(currentDay);
};

import { GameState, InventoryItem, DungeonResult } from '../../types/index';
import { DUNGEONS } from '../../data/dungeons';
import { Expedition } from '../../models/Dungeon';
import { MATERIALS } from '../../data/materials';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
// Add import for MercenaryStatus
import { MercenaryStatus } from '../../models/Mercenary';

export const handleStartExpedition = (state: GameState, payload: { dungeonId: string; partyIds: string[] }): GameState => {
    const { dungeonId, partyIds } = payload;
    const dungeon = DUNGEONS.find(d => d.id === dungeonId);
    if (!dungeon) return state;

    const newExpeditionId = `exp_${Date.now()}`;

    const updatedMercenaries = state.knownMercenaries.map(merc => {
        if (partyIds.includes(merc.id)) {
            return {
                ...merc,
                expeditionEnergy: Math.max(0, (merc.expeditionEnergy || 0) - dungeon.energyCost),
                status: 'ON_EXPEDITION' as const,
                assignedExpeditionId: newExpeditionId
            };
        }
        return merc;
    });

    const newExpedition: Expedition = {
        id: newExpeditionId,
        dungeonId: dungeon.id,
        partyIds: partyIds,
        startTime: Date.now(),
        endTime: Date.now() + (dungeon.durationMinutes * 60 * 1000),
        status: 'ACTIVE'
    };

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeExpeditions: [...state.activeExpeditions, newExpedition],
        logs: [`Expedition sent to ${dungeon.name}.`, ...state.logs]
    };
};

export const handleCompleteExpedition = (state: GameState, payload: { expeditionId: string }): GameState => {
    const { expeditionId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);

    if (!expedition || expedition.status !== 'ACTIVE') return state;

    const dungeon = DUNGEONS.find(d => d.id === expedition.dungeonId);
    const dungeonName = dungeon ? dungeon.name : 'Unknown';

    const updatedExpeditions = state.activeExpeditions.map(exp => {
        if (exp.id === expeditionId) {
            return { ...exp, status: 'COMPLETED' as const };
        }
        return exp;
    });

    return {
        ...state,
        activeExpeditions: updatedExpeditions,
        logs: [`Expedition to ${dungeonName} is ready for return.`, ...state.logs]
    };
};

export const handleAbortExpedition = (state: GameState, payload: { expeditionId: string }): GameState => {
    const { expeditionId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);
    if (!expedition) return state;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (expedition.partyIds.includes(m.id)) {
            return { ...m, status: 'HIRED' as const, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeExpeditions: state.activeExpeditions.filter(e => e.id !== expeditionId),
        logs: [`Mission aborted. The squad has been recalled with no rewards.`, ...state.logs]
    };
};

export const handleClaimExpedition = (state: GameState, payload: { expeditionId: string; rescuedNpcId?: string }): GameState => {
    const { expeditionId, rescuedNpcId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);
    if (!expedition) return state;

    const dungeon = DUNGEONS.find(d => d.id === expedition.dungeonId);
    if (!dungeon) return state;

    const partyMembers = state.knownMercenaries.filter(m => expedition.partyIds.includes(m.id));
    const totalLuck = partyMembers.reduce((sum, m) => sum + (m.stats.luk + m.allocatedStats.luk), 0);
    const avgLuck = totalLuck / (partyMembers.length || 1);
    const luckMultiplier = 1 + (avgLuck * 0.02);

    const gainedItems: { id: string, count: number, name: string }[] = [];
    let newInventory = [...state.inventory];

    dungeon.rewards.forEach(reward => {
            const adjustedChance = reward.chance * luckMultiplier;
            if (Math.random() <= adjustedChance) {
                const quantity = Math.floor(Math.random() * (reward.maxQuantity - reward.minQuantity + 1)) + reward.minQuantity;
                if (quantity > 0) {
                    const materialDef = Object.values(MATERIALS).find(m => m.id === reward.itemId);
                    if (materialDef) {
                        const existingItem = newInventory.find(i => i.id === reward.itemId);
                        if (existingItem) {
                            newInventory = newInventory.map(i => i.id === reward.itemId ? { ...i, quantity: i.quantity + quantity } : i);
                        } else {
                            newInventory.push({ ...materialDef, quantity } as InventoryItem);
                        }
                        gainedItems.push({ id: reward.itemId, count: quantity, name: materialDef.name });
                    }
                }
            }
    });

    const goldGained = dungeon.goldReward || 0;

    const isFirstClear = (state.dungeonClearCounts[dungeon.id] || 0) === 0;
    if (isFirstClear && dungeon.id === 'dungeon_t1_rats') {
        const scrollDef = MATERIALS.recipe_scroll_bronze_longsword;
        const alreadyHasScroll = newInventory.some(i => i.id === scrollDef.id);
        const alreadyHasRecipe = state.unlockedRecipes.includes('sword_bronze_long_t1');

        if (!alreadyHasScroll && !alreadyHasRecipe) {
            newInventory.push({ ...scrollDef, quantity: 1 } as InventoryItem);
            gainedItems.push({ id: scrollDef.id, count: 1, name: scrollDef.name });
        }
    }

    const mercenaryResults: DungeonResult['mercenaryResults'] = [];
    let newKnownMercenaries = [...state.knownMercenaries];

    // Process XP for party and handle health-based status changes
    newKnownMercenaries = newKnownMercenaries.map(merc => {
        if (expedition.partyIds.includes(merc.id)) {
            let xpToAdd = dungeon.baseXp || 50;
            let currentXp = merc.currentXp || 0;
            let xpToNext = merc.xpToNextLevel || (merc.level * 100);
            let level = merc.level;
            const levelBefore = level;

            currentXp += xpToAdd;

            while (currentXp >= xpToNext) {
                currentXp -= xpToNext;
                level++;
                xpToNext = level * 100;
            }

            let maxHp = merc.maxHp;
            let maxMp = merc.maxMp;
            let currentHp = merc.currentHp;

            let bonusStatPoints = merc.bonusStatPoints || 0;
            if (level > levelBefore) {
                const merged = mergePrimaryStats(merc.stats, merc.allocatedStats);
                maxHp = calculateMaxHp(merged, level);
                maxMp = calculateMaxMp(merged, level);
                currentHp = maxHp;
                // Add 3 points per level gained
                bonusStatPoints += (level - levelBefore) * 3;
            }

            // Fix: Explicitly type nextStatus as MercenaryStatus to allow assignment of 'INJURED'
            let nextStatus: MercenaryStatus = 'HIRED';
            let recoveryUntilDay: number | undefined = undefined;

            // If HP < 1, they return INJURED
            if (currentHp < 1) {
                nextStatus = 'INJURED' as const;
                recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 2) + 1;
            }

            mercenaryResults.push({
                id: merc.id,
                name: merc.name,
                job: merc.job,
                levelBefore,
                levelAfter: level,
                xpGained: xpToAdd,
                currentXp: currentXp,
                xpToNext: xpToNext,
                statusChange: currentHp < 1 ? 'INJURED' : 'NONE'
            });

            return {
                ...merc,
                level,
                currentXp,
                xpToNextLevel: xpToNext,
                bonusStatPoints,
                maxHp,
                maxMp,
                currentHp,
                status: nextStatus,
                recoveryUntilDay,
                assignedExpeditionId: undefined
            };
        }
        return merc;
    });

    // Handle Rescued NPC
    let rescuedMercenary = undefined;
    if (rescuedNpcId) {
        if (rescuedNpcId === 'tilly_footloose') {
            rescuedMercenary = { ...TILLY_FOOTLOOSE };
            if (!newKnownMercenaries.some(m => m.id === rescuedMercenary!.id)) {
                newKnownMercenaries.push(rescuedMercenary);
            }
        }
    }

    const newClearCounts = { ...state.dungeonClearCounts };
    newClearCounts[dungeon.id] = (newClearCounts[dungeon.id] || 0) + 1;
    const remainingExpeditions = state.activeExpeditions.filter(e => e.id !== expeditionId);

    const resultData: DungeonResult = {
        dungeonName: dungeon.name,
        rewards: gainedItems,
        goldGained,
        mercenaryResults,
        rescuedMercenary
    };

    const luckMsg = luckMultiplier > 1.1 ? ` (Luck Bonus x${luckMultiplier.toFixed(1)})` : '';
    let logStr = gainedItems.length > 0 
        ? `Returned from ${dungeon.name}${luckMsg}. Gained: ${gainedItems.map(i => `${i.name} x${i.count}`).join(', ')}`
        : `Returned from ${dungeon.name}. No loot found.`;

    if (goldGained > 0) logStr += ` and ${goldGained} Gold.`;

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newKnownMercenaries,
        activeExpeditions: remainingExpeditions,
        dungeonClearCounts: newClearCounts,
        dungeonResult: resultData,
        stats: {
            ...state.stats,
            gold: state.stats.gold + goldGained,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeDungeon: state.stats.dailyFinancials.incomeDungeon + goldGained
            }
        },
        logs: [logStr, ...state.logs]
    };
};

export const handleDismissDungeonResult = (state: GameState): GameState => {
    return { ...state, dungeonResult: null };
