import { MercenaryStatus } from '../../models/Mercenary';

export const handleStartExpedition = (state: GameState, payload: { dungeonId: string; partyIds: string[] }): GameState => {
    const { dungeonId, partyIds } = payload;
    const dungeon = DUNGEONS.find(d => d.id === dungeonId);
    if (!dungeon) return state;

    const newExpeditionId = `exp_${Date.now()}`;

    const updatedMercenaries = state.knownMercenaries.map(merc => {
        if (partyIds.includes(merc.id)) {
            return {
                ...merc,
                expeditionEnergy: Math.max(0, (merc.expeditionEnergy || 0) - dungeon.energyCost),
                status: 'ON_EXPEDITION' as const,
                assignedExpeditionId: newExpeditionId
            };
        }
        return merc;
    });

    const newExpedition: Expedition = {
        id: newExpeditionId,
        dungeonId: dungeon.id,
        partyIds: partyIds,
        startTime: Date.now(),
        endTime: Date.now() + (dungeon.durationMinutes * 60 * 1000),
        status: 'ACTIVE'
    };

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeExpeditions: [...state.activeExpeditions, newExpedition],
        logs: [`Expedition sent to ${dungeon.name}.`, ...state.logs]
    };
};

export const handleCompleteExpedition = (state: GameState, payload: { expeditionId: string }): GameState => {
    const { expeditionId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);

    if (!expedition || expedition.status !== 'ACTIVE') return state;

    const dungeon = DUNGEONS.find(d => d.id === expedition.dungeonId);
    const dungeonName = dungeon ? dungeon.name : 'Unknown';

    const updatedExpeditions = state.activeExpeditions.map(exp => {
        if (exp.id === expeditionId) {
            return { ...exp, status: 'COMPLETED' as const };
        }
        return exp;
    });

    return {
        ...state,
        activeExpeditions: updatedExpeditions,
        logs: [`Expedition to ${dungeonName} is ready for return.`, ...state.logs]
    };
};

export const handleAbortExpedition = (state: GameState, payload: { expeditionId: string }): GameState => {
    const { expeditionId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);
    if (!expedition) return state;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (expedition.partyIds.includes(m.id)) {
            return { ...m, status: 'HIRED' as const, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeExpeditions: state.activeExpeditions.filter(e => e.id !== expeditionId),
        logs: [`Mission aborted. The squad has been recalled with no rewards.`, ...state.logs]
    };
};

export const handleClaimExpedition = (state: GameState, payload: { expeditionId: string; rescuedNpcId?: string }): GameState => {
    const { expeditionId, rescuedNpcId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);
    if (!expedition) return state;

    const dungeon = DUNGEONS.find(d => d.id === expedition.dungeonId);
    if (!dungeon) return state;

    const partyMembers = state.knownMercenaries.filter(m => expedition.partyIds.includes(m.id));
    const totalLuck = partyMembers.reduce((sum, m) => sum + (m.stats.luk + m.allocatedStats.luk), 0);
    const avgLuck = totalLuck / (partyMembers.length || 1);
    const luckMultiplier = 1 + (avgLuck * 0.02);

    const gainedItems: { id: string, count: number, name: string }[] = [];
    let newInventory = [...state.inventory];

    dungeon.rewards.forEach(reward => {
            const adjustedChance = reward.chance * luckMultiplier;
            if (Math.random() <= adjustedChance) {
                const quantity = Math.floor(Math.random() * (reward.maxQuantity - reward.minQuantity + 1)) + reward.minQuantity;
                if (quantity > 0) {
                    const materialDef = Object.values(MATERIALS).find(m => m.id === reward.itemId);
                    if (materialDef) {
                        const existingItem = newInventory.find(i => i.id === reward.itemId);
                        if (existingItem) {
                            newInventory = newInventory.map(i => i.id === reward.itemId ? { ...i, quantity: i.quantity + quantity } : i);
                        } else {
                            newInventory.push({ ...materialDef, quantity } as InventoryItem);
                        }
                        gainedItems.push({ id: reward.itemId, count: quantity, name: materialDef.name });
                    }
                }
            }
    });

    const goldGained = dungeon.goldReward || 0;

    const isFirstClear = (state.dungeonClearCounts[dungeon.id] || 0) === 0;
    if (isFirstClear && dungeon.id === 'dungeon_t1_rats') {
        const scrollDef = MATERIALS.recipe_scroll_bronze_longsword;
        const alreadyHasScroll = newInventory.some(i => i.id === scrollDef.id);
        const alreadyHasRecipe = state.unlockedRecipes.includes('sword_bronze_long_t1');

        if (!alreadyHasScroll && !alreadyHasRecipe) {
            newInventory.push({ ...scrollDef, quantity: 1 } as InventoryItem);
            gainedItems.push({ id: scrollDef.id, count: 1, name: scrollDef.name });
        }
    }

    const mercenaryResults: DungeonResult['mercenaryResults'] = [];
    let newKnownMercenaries = [...state.knownMercenaries];

    // Process XP for party and handle health-based status changes
    newKnownMercenaries = newKnownMercenaries.map(merc => {
        if (expedition.partyIds.includes(merc.id)) {
            let xpToAdd = dungeon.baseXp || 50;
            let currentXp = merc.currentXp || 0;
            let xpToNext = merc.xpToNextLevel || (merc.level * 100);
            let level = merc.level;
            const levelBefore = level;

            currentXp += xpToAdd;

            while (currentXp >= xpToNext) {
                currentXp -= xpToNext;
                level++;
                xpToNext = level * 100;
            }

            let maxHp = merc.maxHp;
            let maxMp = merc.maxMp;
            let currentHp = merc.currentHp;

            let bonusStatPoints = merc.bonusStatPoints || 0;
            if (level > levelBefore) {
                const merged = mergePrimaryStats(merc.stats, merc.allocatedStats);
                maxHp = calculateMaxHp(merged, level);
                maxMp = calculateMaxMp(merged, level);
                currentHp = maxHp;
                // Add 3 points per level gained
                bonusStatPoints += (level - levelBefore) * 3;
            }

            // Fix: Explicitly type nextStatus as MercenaryStatus to allow assignment of 'INJURED'
            let nextStatus: MercenaryStatus = 'HIRED';
            let recoveryUntilDay: number | undefined = undefined;

            // If HP < 1, they return INJURED
            if (currentHp < 1) {
                nextStatus = 'INJURED' as const;
                recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 2) + 1;
            }

            mercenaryResults.push({
                id: merc.id,
                name: merc.name,
                job: merc.job,
                levelBefore,
                levelAfter: level,
                xpGained: xpToAdd,
                currentXp: currentXp,
                xpToNext: xpToNext,
                statusChange: currentHp < 1 ? 'INJURED' : 'NONE'
            });

            return {
                ...merc,
                level,
                currentXp,
                xpToNextLevel: xpToNext,
                bonusStatPoints,
                maxHp,
                maxMp,
                currentHp,
                status: nextStatus,
                recoveryUntilDay,
                assignedExpeditionId: undefined
            };
        }
        return merc;
    });

    // Handle Rescued NPC
    let rescuedMercenary = undefined;
    if (rescuedNpcId) {
        if (rescuedNpcId === 'tilly_footloose') {
            rescuedMercenary = { ...TILLY_FOOTLOOSE };
            if (!newKnownMercenaries.some(m => m.id === rescuedMercenary!.id)) {
                newKnownMercenaries.push(rescuedMercenary);
            }
        }
    }

    const newClearCounts = { ...state.dungeonClearCounts };
    newClearCounts[dungeon.id] = (newClearCounts[dungeon.id] || 0) + 1;
    const remainingExpeditions = state.activeExpeditions.filter(e => e.id !== expeditionId);

    const resultData: DungeonResult = {
        dungeonName: dungeon.name,
        rewards: gainedItems,
        goldGained,
        mercenaryResults,
        rescuedMercenary
    };

    const luckMsg = luckMultiplier > 1.1 ? ` (Luck Bonus x${luckMultiplier.toFixed(1)})` : '';
    let logStr = gainedItems.length > 0 
        ? `Returned from ${dungeon.name}${luckMsg}. Gained: ${gainedItems.map(i => `${i.name} x${i.count}`).join(', ')}`
        : `Returned from ${dungeon.name}. No loot found.`;

    if (goldGained > 0) logStr += ` and ${goldGained} Gold.`;

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newKnownMercenaries,
        activeExpeditions: remainingExpeditions,
        dungeonClearCounts: newClearCounts,
        dungeonResult: resultData,
        stats: {
            ...state.stats,
            gold: state.stats.gold + goldGained,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeDungeon: state.stats.dailyFinancials.incomeDungeon + goldGained
            }
        },
        logs: [logStr, ...state.logs]
    };
};

export const handleDismissDungeonResult = (state: GameState): GameState => {
    return { ...state, dungeonResult: null };
};

import { GameState } from '../../types/index';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';
import { PrimaryStats, mergePrimaryStats, calculateMaxHp, calculateMaxMp } from '../../models/Stats';
import { EquipmentRarity } from '../../models/Equipment';

export const handleAddKnownMercenary = (state: GameState, merc: Mercenary): GameState => {
    if (state.knownMercenaries.some(m => m.id === merc.id)) return state;
    const mercWithData = { 
        ...merc, 
        expeditionEnergy: merc.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: merc.currentXp ?? 0,
        xpToNextLevel: merc.xpToNextLevel ?? (merc.level * 100),
        status: 'VISITOR' as const,
        bonusStatPoints: merc.bonusStatPoints ?? 0
    };
    return {
        ...state,
        knownMercenaries: [...state.knownMercenaries, mercWithData],
        logs: [`${merc.name} is now a regular at the tavern.`, ...state.logs]
    };
};

export const handleScoutMercenary = (state: GameState, payload: { mercenary: Mercenary; cost: number }): GameState => {
    const { mercenary, cost } = payload;
    if (state.stats.gold < cost) return state;

    const mercWithData = { 
        ...mercenary, 
        expeditionEnergy: mercenary.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: mercenary.currentXp ?? 0,
        xpToNextLevel: mercenary.xpToNextLevel ?? (mercenary.level * 100),
        status: 'VISITOR' as const,
        bonusStatPoints: mercenary.bonusStatPoints ?? 0
    };

    return {
        ...state,
        stats: {
            ...state.stats,
            gold: state.stats.gold - cost,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseScout: state.stats.dailyFinancials.expenseScout + cost
            }
        },
        knownMercenaries: [...state.knownMercenaries, mercWithData],
        logs: [`Paid ${cost} G to find new talent. ${mercenary.name} arrived at the tavern.`, ...state.logs]
    };
};

export const handleHireMercenary = (state: GameState, payload: { mercenaryId: string; cost: number }): GameState => {
    const { mercenaryId, cost } = payload;
    if (state.stats.gold < cost) return state;

    let newUnlockedTabs = [...state.unlockedTabs];
    let logUpdates: string[] = [];

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (m.id === mercenaryId) return { ...m, status: 'HIRED' as const };
        return m;
    });

    const hiredMerc = updatedMercenaries.find(m => m.id === mercenaryId);
    const name = hiredMerc ? hiredMerc.name : 'Mercenary';
    logUpdates.push(`Contract signed! ${name} has joined your service. -${cost} G`);

    if (!newUnlockedTabs.includes('DUNGEON')) {
        newUnlockedTabs.push('DUNGEON');
        logUpdates.unshift("Objective Unlocked: You can now deploy squads to explore Dungeons.");
    }

    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold - cost,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseScout: state.stats.dailyFinancials.expenseScout + cost
            }
        },
        knownMercenaries: updatedMercenaries,
        unlockedTabs: newUnlockedTabs,
        logs: [...logUpdates, ...state.logs]
    };
};

export const handleFireMercenary = (state: GameState, payload: { mercenaryId: string }): GameState => {
    const { mercenaryId } = payload;
    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (m.id === mercenaryId) return { ...m, status: 'VISITOR' as const };
        return m;
    });
    const firedMerc = updatedMercenaries.find(m => m.id === mercenaryId);
    const name = firedMerc ? firedMerc.name : 'Mercenary';
    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        logs: [`Contract terminated. ${name} is no longer in your service.`, ...state.logs]
    };
};

export const handleGiveGift = (state: GameState, payload: { mercenaryId: string; itemId: string }): GameState => {
    const { mercenaryId, itemId } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const inventoryItem = state.inventory.find(i => i.id === itemId);
    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    const mercenary = { ...state.knownMercenaries[mercIndex] };
    let affinityGain = 3; 
    let staminaGain = 0;
    let qualityNote = "";

    // Special handling for consumables
    if (itemId === 'stamina_potion') {
        staminaGain = 50;
        affinityGain = 5;
    } else if (itemId === 'affinity_debug_gift') {
        affinityGain = 50;
    } else if (inventoryItem.type === 'EQUIPMENT' && inventoryItem.equipmentData) {
        affinityGain = 5; // Base for gear
        // Rarity bonus
        switch (inventoryItem.equipmentData.rarity) {
            case EquipmentRarity.UNCOMMON: affinityGain += 2; break;
            case EquipmentRarity.RARE: affinityGain += 4; break;
            case EquipmentRarity.EPIC: affinityGain += 7; break;
            case EquipmentRarity.LEGENDARY: affinityGain += 12; break;
        }

        // Quality bonus/penalty
        const q = inventoryItem.equipmentData.quality;
        if (q > 100) {
            affinityGain += 5;
            qualityNote = " (Pristine Quality Bonus!)";
        } else if (q < 80) {
            affinityGain = Math.max(1, Math.floor(affinityGain * 0.4));
            qualityNote = " (Low Quality Penalty)";
        }
    }

    mercenary.affinity = Math.min(100, (mercenary.affinity || 0) + affinityGain);
    if (staminaGain > 0) {
        mercenary.expeditionEnergy = Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (mercenary.expeditionEnergy || 0) + staminaGain);
    }

    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = mercenary;

    let logMsg = `Gifted ${inventoryItem.name} to ${mercenary.name}. Affinity +${affinityGain}${qualityNote}.`;
    if (staminaGain > 0) logMsg += ` Stamina +${staminaGain}.`;

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [logMsg, ...state.logs]
    };
};

export const handleTalkMercenary = (state: GameState, payload: { mercenaryId: string }): GameState => {
    const { mercenaryId } = payload;
    if (state.talkedToToday.includes(mercenaryId)) return state;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const newMercenaries = [...state.knownMercenaries];
    const merc = { ...newMercenaries[mercIndex] };
    merc.affinity = Math.min(100, (merc.affinity || 0) + 1);
    newMercenaries[mercIndex] = merc;

    return {
        ...state,
        knownMercenaries: newMercenaries,
        talkedToToday: [...state.talkedToToday, mercenaryId],
        logs: [`Talked with ${merc.name}. Affinity +1.`, ...state.logs]
    };
};

export const handleAllocateStat = (state: GameState, payload: { mercenaryId: string; stat: keyof PrimaryStats }): GameState => {
    const { mercenaryId, stat } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const merc = state.knownMercenaries[mercIndex];
    if ((merc.bonusStatPoints || 0) <= 0) return state;

    const newAllocated = { ...merc.allocatedStats, [stat]: merc.allocatedStats[stat] + 1 };
    const merged = mergePrimaryStats(merc.stats, newAllocated);

    // Vitals update
    const newMaxHp = calculateMaxHp(merged, merc.level);
    const newMaxMp = calculateMaxMp(merged, merc.level);
    // Heal proportional to hp increase
    const hpGain = newMaxHp - merc.maxHp;
    const mpGain = newMaxMp - merc.maxMp;

    const updatedMerc: Mercenary = {
        ...merc,
        allocatedStats: newAllocated,
        bonusStatPoints: merc.bonusStatPoints - 1, // Consume point
        maxHp: newMaxHp,
        currentHp: merc.currentHp + (hpGain > 0 ? hpGain : 0),
        maxMp: newMaxMp,
        currentMp: merc.currentMp + (mpGain > 0 ? mpGain : 0)
    };

    const newKnownMercenaries = [...state.knownMercenaries];
    newKnownMercenaries[mercIndex] = updatedMerc;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries
    };
};

export const handleUpdateMercenaryStats = (state: GameState, payload: { mercenaryId: string; stats: PrimaryStats }): GameState => {
    const { mercenaryId, stats } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const merc = state.knownMercenaries[mercIndex];

    const merged = mergePrimaryStats(merc.stats, stats);
    const newMaxHp = calculateMaxHp(merged, merc.level);
    const newMaxMp = calculateMaxMp(merged, merc.level);

    // Maintain current health percentage if possible, or just add the flat difference
    const hpDiff = newMaxHp - merc.maxHp;
    const mpDiff = newMaxMp - merc.maxMp;

    const updatedMerc: Mercenary = {
        ...merc,
        allocatedStats: stats,
        maxHp: newMaxHp,
        maxMp: newMaxMp,
        currentHp: merc.currentHp + (hpDiff > 0 ? hpDiff : 0),
        currentMp: merc.currentMp + (mpDiff > 0 ? mpDiff : 0)
    };

    const newKnownMercenaries = [...state.knownMercenaries];
    newKnownMercenaries[mercIndex] = updatedMerc;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        logs: [`Updated attributes for ${merc.name}.`, ...state.logs]
    };
};

import { GameState, ManualDungeonSession, RoomType, DungeonResult } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { MONSTERS } from '../../data/monsters';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';

// Helper to generate the dungeon grid for manual assault mode
const generateManualGrid = (width: number, height: number, dungeonId: string): RoomType[][] => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    // Entry point is always at the top-left
    grid[0][0] = 'ENTRANCE';

    // Boss room is typically at the bottom-right
    grid[height - 1][width - 1] = 'BOSS';

    // Randomly place exactly one key required for some dungeons
    let keyPlaced = false;
    let attempts = 0;
    while (!keyPlaced && attempts < 100) {
        let kx = Math.floor(Math.random() * width);
        let ky = Math.floor(Math.random() * height);
        if (grid[ky][kx] === 'EMPTY') {
            grid[ky][kx] = 'KEY';
            keyPlaced = true;
        }
        attempts++;
    }

    // Populate the rest of the grid with random points of interest
    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const r = Math.random();
                if (r < 0.12) grid[y][x] = 'GOLD';
                else if (r < 0.22) grid[y][x] = 'TRAP';
                else if (r < 0.25) grid[y][x] = 'NPC';
            }
        }
    }

    return grid;
};

/**
 * handleStartManualDungeon
 * Initializes a new manual dungeon session, consumes entry energy, and prepares the grid.
 */
export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string; partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const party = state.knownMercenaries.filter(m => payload.partyIds.includes(m.id));
    if (party.some(m => (m.expeditionEnergy || 0) < dungeon.energyCost)) {
        return { ...state, logs: [`Your squad is too exhausted to enter ${dungeon.name}.`, ...state.logs] };
    }

    // Update mercenary status and energy levels
    const updatedMercs = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { 
                ...m, 
                expeditionEnergy: Math.max(0, (m.expeditionEnergy || 0) - dungeon.energyCost), 
                status: 'ON_EXPEDITION' as const 
            };
        }
        return m;
    });

    const grid = generateManualGrid(dungeon.gridWidth, dungeon.gridHeight, dungeon.id);
    const visited = Array.from({ length: dungeon.gridHeight }, () => Array(dungeon.gridWidth).fill(false));
    // Reveal the starting location
    visited[0][0] = true;

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos: { x: 0, y: 0 },
        pathHistory: [{ x: 0, y: 0 }],
        hasKey: false,
        isBossLocked: dungeon.isBossLocked ?? true,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Direct assault initiated: ${dungeon.name}.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { ...state, toastQueue: [...state.toastQueue, "Area boundary reached."] };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    // 전멸 체크: 모든 파티원의 체력이 0이 되면 탈락
    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) {
        return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });
    }

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Squad hit by a trap! (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: Boss identified.`;
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

/**
 * handleFinishManualDungeon
 * Successfully concludes a manual dungeon run, processing rewards and clearing the session.
 */
export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    // We reuse handleClaimExpedition by simulating a completed expedition object
    const tempExpId = `temp_manual_${Date.now()}`;
    const tempExp = {
        id: tempExpId,
        dungeonId: session.dungeonId,
        partyIds: session.partyIds,
        startTime: 0,
        endTime: 0,
        status: 'COMPLETED' as const
    };

    const stateWithTempExp = {
        ...state,
        activeExpeditions: [...state.activeExpeditions, tempExp]
    };

    // Calculate standard rewards and potential NPC rescues
    const claimedState = handleClaimExpedition(stateWithTempExp, { 
        expeditionId: tempExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    // Finalize manually collected currency
    if (session.goldCollected > 0) {
        claimedState.stats.gold += session.goldCollected;
        if (claimedState.dungeonResult) {
            claimedState.dungeonResult.goldGained = (claimedState.dungeonResult.goldGained || 0) + session.goldCollected;
        }
    }

    return {
        ...claimedState,
        activeManualDungeon: null,
        showManualDungeonOverlay: false
    };
};

/**
 * handleStartCombatManual
 * Spawns the boss monster and transitions the session into the combat view.
 */
export const handleStartCombatManual = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus !== 'ENCOUNTERED') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    // Select boss based on dungeon variant availability and player clears
    let bossId = 'rat_man'; 
    if (dungeon.bossVariantId && MONSTERS[dungeon.bossVariantId]) {
        const clears = state.dungeonClearCounts[dungeon.id] || 0;
        if (clears >= (dungeon.bossUnlockReq || 0)) {
            bossId = dungeon.bossVariantId;
        }
    }

    const monsterBase = MONSTERS[bossId] || MONSTERS['rat_man'];
    const bossEntity = { ...monsterBase, currentHp: monsterBase.stats.maxHp };

    return {
        ...state,
        activeManualDungeon: {
            ...session,
            encounterStatus: 'BATTLE',
            bossEntity
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    let logMsg = '';

    // 경험치 분배: 승리 시 보스 경험치를 생존 파티원 수로 나눔
    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);
    const xpPerMember = (payload.win && session.bossEntity && livingMembers.length > 0) 
        ? Math.floor(session.bossEntity.rewardXp / livingMembers.length) 
        : 0;

    if (payload.win && xpPerMember > 0) {
        logMsg = `VICTORY: ${session.bossEntity?.name} defeated! ${livingMembers.length} members gained ${xpPerMember} XP.`;
    }

    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;
            let bonusStatPoints = m.bonusStatPoints || 0;

            if (payload.win && combatant.currentHp > 0) {
                nextXp += xpPerMember;
                while (nextXp >= m.xpToNextLevel) {
                    const levelGain = 1;
                    nextXp -= m.xpToNextLevel;
                    nextLevel++;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp; // 레벨업 시 완치
                    bonusStatPoints += 3; // Add 3 points per level gained
                    logMsg += ` ${m.name} reached Level ${nextLevel}!`;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                bonusStatPoints,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated: payload.win || session.isBossDefeated
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: Squad neutralized.' : 'Squad retreated.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Survivor secured! Initiating extraction.`, ...state.logs]
    };
};

